      "path": "src/modules/projects/tasks/controller.js",
      "content": "const { randomUUID } = require('../../lib/id');

const tasks = [];

const create = (req, res) => {
  const { title } = req.body;
  if (!title) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Title is required' } });
  }
  const task = { id: randomUUID(), title, status: 'pending' };
  tasks.push(task);
  res.status(201).json({ task });
};

const getAll = (req, res) => {
  res.json(tasks);
};

const get = (req, res) => {
  const { taskId } = req.params;
  const task = tasks.find(t => t.id === taskId);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task });
};

const patch = (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Status is required' } });
  }
  const task = tasks.find(t => t.id === taskId);
  if (!task) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  task.status = status;
  res.json({ task });
};

module.exports = { create, getAll, get, patch };
